import { useState } from "react";

const THEMES = [
  { id: "default", label: "Cosmic",  colors: ["#5b8def","#8b5cf6","#06d6a0","#f59e0b"] },
  { id: "blue",    label: "Ocean",   colors: ["#0ea5e9","#38bdf8","#7dd3fc","#bae6fd"] },
  { id: "warm",    label: "Sunset",  colors: ["#f97316","#fb923c","#fbbf24","#f43f5e"] },
  { id: "dark",    label: "Neon",    colors: ["#a78bfa","#34d399","#fb7185","#fbbf24"] },
];

const QUICK = [
  "Revenue by category, sales by region, monthly profit trend",
  "Top 10 customers by sales, order count by ship mode",
  "Sales vs profit by sub-category, discount impact",
  "Monthly sales trend, orders by segment, top products",
];

export default function InputForm({ connectionData, onSubmit, loading }) {
  const [query, setQuery]           = useState("");
  const [numViz, setNumViz]         = useState(3);
  const [colorSchema, setColor]     = useState("default");
  const [title, setTitle]           = useState("My Dashboard");
  const [queryFocused, setQFocused] = useState(false);

  const submit = () => {
    if (!query.trim()) return;
    onSubmit({ session_id: connectionData.session_id, user_query: query, num_visualizations: numViz, color_schema: colorSchema, dashboard_title: title });
  };

  return (
    <div style={S.wrap}>
      {/* Topbar */}
      <div style={S.bar}>
        <div style={S.barLeft}>
          <div style={S.logo}>
            <svg width="18" height="18" viewBox="0 0 28 28" fill="none">
              <circle cx="14" cy="14" r="12.5" stroke="#5b8def" strokeWidth="1.5"/>
              <path d="M8 19 L12 9 L16 15 L20 7" stroke="#5b8def" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
              <circle cx="20" cy="7" r="2" fill="#8b5cf6"/>
            </svg>
          </div>
          <span style={S.logoTxt}>Talking BI</span>
        </div>
        <div style={S.pill}>
          <div style={S.dot} />
          {connectionData.tables?.length} tables connected
        </div>
      </div>

      {/* Body */}
      <div style={S.body}>
        {/* Left form */}
        <div style={S.left}>
          <div style={S.formHead}>
            <h2 style={S.h2}>Build your dashboard</h2>
            <p style={S.p}>Describe what you want to see in plain English</p>
          </div>

          {/* Title */}
          <Field label="Dashboard title">
            <input style={S.inp} value={title} onChange={(e) => setTitle(e.target.value)} placeholder="e.g. Sales Analytics 2024" />
          </Field>

          {/* Query */}
          <Field label="What do you want to visualize?">
            <textarea
              style={{ ...S.textarea, ...(queryFocused ? S.textareaFocus : {}) }}
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              onFocus={() => setQFocused(true)}
              onBlur={() => setQFocused(false)}
              placeholder="e.g. revenue by category, sales by region, monthly profit trend..."
              rows={4}
            />
          </Field>

          {/* Quick examples */}
          <Field label="Quick examples">
            <div style={S.quickList}>
              {QUICK.map((q, i) => (
                <button key={i} style={S.quickBtn} onClick={() => setQuery(q)}>
                  <span style={S.qArrow}>→</span> {q}
                </button>
              ))}
            </div>
          </Field>

          {/* Num charts */}
          <Field label={<>Number of charts <span style={S.badge}>{numViz}</span></>}>
            <div style={S.numRow}>
              {[2,3,4,5,6].map((n) => (
                <button key={n} style={{ ...S.numBtn, ...(numViz===n ? S.numBtnOn : {}) }} onClick={() => setNumViz(n)}>{n}</button>
              ))}
            </div>
          </Field>

          {/* Color theme */}
          <Field label="Color theme">
            <div style={S.themeRow}>
              {THEMES.map((t) => (
                <button key={t.id} style={{ ...S.themeBtn, ...(colorSchema===t.id ? S.themeBtnOn : {}) }} onClick={() => setColor(t.id)}>
                  <div style={S.swatches}>
                    {t.colors.map((c,i) => <div key={i} style={{ width:12, height:12, borderRadius:3, background:c }} />)}
                  </div>
                  <span style={S.themeLbl}>{t.label}</span>
                </button>
              ))}
            </div>
          </Field>

          {/* Submit */}
          <button
            style={{ ...S.submit, ...(loading || !query.trim() ? S.submitOff : {}) }}
            onClick={submit}
            disabled={loading || !query.trim()}
          >
            {loading ? (
              <><span style={S.spinner}/>Generating dashboard...</>
            ) : (
              <><svg width="16" height="16" viewBox="0 0 16 16" fill="none"><path d="M2 8h12M8 2l6 6-6 6" stroke="#fff" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/></svg>Generate Dashboard</>
            )}
          </button>
        </div>

        {/* Right schema panel */}
        <div style={S.right}>
          <p style={S.schemaTitle}>
            <svg width="13" height="13" viewBox="0 0 13 13" fill="none" style={{ marginRight:6 }}>
              <rect x=".5" y=".5" width="12" height="12" rx="2" stroke="#5b8def" strokeWidth="1.2"/>
              <path d=".5 4.5h12M4.5 4.5v8" stroke="#5b8def" strokeWidth="1.2"/>
            </svg>
            Connected Schema
          </p>
          <div style={S.tableList}>
            {connectionData.tables?.map((t) => (
              <div key={t.table_name} style={S.tableCard}>
                <div style={S.tableHead}>
                  <span style={S.tableName}>{t.table_name}</span>
                  <span style={S.tableCount}>{t.row_count.toLocaleString()} rows</span>
                </div>
                <div style={S.cols}>
                  {t.columns.slice(0,5).map((c) => (
                    <div key={c.name} style={S.col}>
                      <span style={S.colName}>{c.name}</span>
                      <span style={S.colType}>{c.type.split("(")[0].toLowerCase()}</span>
                    </div>
                  ))}
                  {t.columns.length > 5 && <div style={S.more}>+{t.columns.length-5} more</div>}
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

function Field({ label, children }) {
  return (
    <div style={{ marginBottom: 24 }}>
      <label style={{ display:"flex", alignItems:"center", gap:8, fontSize:11, fontWeight:700, color:"var(--text2)", textTransform:"uppercase", letterSpacing:"0.08em", marginBottom:10 }}>{label}</label>
      {children}
    </div>
  );
}

const S = {
  wrap: { minHeight:"100vh", display:"flex", flexDirection:"column" },
  bar:  { padding:"13px 28px", borderBottom:"1px solid var(--border)", display:"flex", alignItems:"center", justifyContent:"space-between", background:"rgba(7,9,15,0.92)", backdropFilter:"blur(12px)", position:"sticky", top:0, zIndex:10 },
  barLeft: { display:"flex", alignItems:"center", gap:10 },
  logo: { width:34, height:34, background:"rgba(91,141,239,0.1)", border:"1px solid rgba(91,141,239,0.18)", borderRadius:10, display:"flex", alignItems:"center", justifyContent:"center" },
  logoTxt: { fontFamily:"'Syne',sans-serif", fontWeight:800, fontSize:17, color:"#fff" },
  pill: { display:"flex", alignItems:"center", gap:7, padding:"5px 14px", background:"rgba(6,214,160,0.08)", border:"1px solid rgba(6,214,160,0.2)", borderRadius:20, color:"var(--accent3)", fontSize:12, fontWeight:500 },
  dot:  { width:7, height:7, borderRadius:"50%", background:"var(--accent3)", animation:"pulse 2s infinite" },
  body: { flex:1, display:"flex" },
  left: { flex:1, padding:"40px 48px", maxWidth:680, overflowY:"auto" },
  formHead: { marginBottom:32 },
  h2:   { fontSize:26, fontWeight:800, color:"#fff", letterSpacing:"-0.5px", marginBottom:6 },
  p:    { fontSize:13, color:"var(--text2)" },
  inp:  { width:"100%", padding:"11px 14px", background:"var(--bg3)", border:"1px solid var(--border2)", borderRadius:"var(--radius)", color:"var(--text)", fontSize:13, outline:"none", fontFamily:"'DM Sans',sans-serif" },
  textarea: { width:"100%", padding:"13px 14px", background:"var(--bg3)", border:"1px solid var(--border2)", borderRadius:"var(--radius)", color:"var(--text)", fontSize:13, outline:"none", resize:"vertical", fontFamily:"'DM Sans',sans-serif", lineHeight:1.65, transition:"border-color 0.2s" },
  textareaFocus: { borderColor:"rgba(91,141,239,0.45)" },
  quickList: { display:"flex", flexDirection:"column", gap:7 },
  quickBtn: { padding:"9px 13px", background:"var(--bg3)", border:"1px solid var(--border)", borderRadius:"var(--radius)", color:"var(--text2)", fontSize:13, cursor:"pointer", textAlign:"left", display:"flex", alignItems:"flex-start", gap:8 },
  qArrow: { color:"var(--accent)", fontWeight:700, flexShrink:0 },
  badge: { background:"var(--accent)", color:"#fff", borderRadius:20, padding:"1px 8px", fontSize:11, fontWeight:700 },
  numRow: { display:"flex", gap:9 },
  numBtn: { width:46, height:46, background:"var(--bg3)", border:"1px solid var(--border2)", borderRadius:"var(--radius)", color:"var(--text2)", fontSize:15, fontWeight:600, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center" },
  numBtnOn: { background:"rgba(91,141,239,0.12)", border:"1px solid rgba(91,141,239,0.45)", color:"var(--accent)" },
  themeRow: { display:"flex", gap:10, flexWrap:"wrap" },
  themeBtn: { padding:"10px 14px", background:"var(--bg3)", border:"1px solid var(--border2)", borderRadius:"var(--radius)", cursor:"pointer", display:"flex", flexDirection:"column", alignItems:"center", gap:7, transition:"all 0.15s" },
  themeBtnOn: { border:"1px solid rgba(91,141,239,0.5)", background:"rgba(91,141,239,0.08)" },
  swatches: { display:"flex", gap:4 },
  themeLbl: { fontSize:11, color:"var(--text2)", fontWeight:600 },
  submit: { width:"100%", padding:"14px", background:"linear-gradient(135deg,#5b8def,#8b5cf6)", border:"none", borderRadius:"var(--radius)", color:"#fff", fontSize:15, fontWeight:700, fontFamily:"'Syne',sans-serif", cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", gap:9, letterSpacing:"0.02em" },
  submitOff: { opacity:0.5, cursor:"not-allowed" },
  spinner: { width:16, height:16, border:"2px solid rgba(255,255,255,0.25)", borderTopColor:"#fff", borderRadius:"50%", animation:"spin 0.7s linear infinite", display:"inline-block" },
  right: { width:290, borderLeft:"1px solid var(--border)", padding:"28px 22px", background:"var(--bg2)", overflowY:"auto" },
  schemaTitle: { display:"flex", alignItems:"center", fontSize:11, fontWeight:700, color:"var(--text2)", textTransform:"uppercase", letterSpacing:"0.08em", marginBottom:18 },
  tableList: { display:"flex", flexDirection:"column", gap:14 },
  tableCard: { background:"var(--bg3)", border:"1px solid var(--border)", borderRadius:"var(--radius)", overflow:"hidden" },
  tableHead: { display:"flex", justifyContent:"space-between", alignItems:"center", padding:"9px 13px", borderBottom:"1px solid var(--border)" },
  tableName: { fontSize:12, fontWeight:700, color:"var(--accent)" },
  tableCount: { fontSize:10, color:"var(--text3)" },
  cols: { padding:"6px 0" },
  col:  { display:"flex", justifyContent:"space-between", padding:"3px 13px" },
  colName: { fontSize:11, color:"var(--text2)" },
  colType: { fontSize:10, color:"var(--text3)", fontFamily:"monospace" },
  more: { padding:"3px 13px", fontSize:10, color:"var(--text3)", fontStyle:"italic" },
};
